import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';

interface Attendance {
  id: number;
  staffName: string;
  date: string;
  checkIn: string | null;
  checkOut: string | null;
  status: 'present' | 'absent' | 'late' | 'half-day';
}

export default function AttendanceList() {
  const [attendance, setAttendance] = useState<Attendance[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const mockData: Attendance[] = [
      { id: 1, staffName: 'John Doe', date: '2026-06-12', checkIn: '09:00', checkOut: '17:30', status: 'present' },
      { id: 2, staffName: 'Jane Smith', date: '2026-06-12', checkIn: '09:15', checkOut: '17:30', status: 'late' },
      { id: 3, staffName: 'Bob Johnson', date: '2026-06-12', checkIn: null, checkOut: null, status: 'absent' },
    ];
    
    setAttendance(mockData);
    setLoading(false);
  }, []);

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      present: 'bg-green-100 text-green-800',
      late: 'bg-yellow-100 text-yellow-800',
      absent: 'bg-red-100 text-red-800',
      'half-day': 'bg-blue-100 text-blue-800',
    };
    return colors[status] || 'bg-gray-100 text-gray-800';
  };

  if (loading) return <div className="p-6">Loading...</div>;

  return (
    <div className="p-6 space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">Attendance</h1>
        <Button>Download Report</Button>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full">
          <thead>
            <tr className="border-b">
              <th className="text-left p-2">Name</th>
              <th className="text-left p-2">Date</th>
              <th className="text-left p-2">Check In</th>
              <th className="text-left p-2">Check Out</th>
              <th className="text-left p-2">Status</th>
            </tr>
          </thead>
          <tbody>
            {attendance.map(a => (
              <tr key={a.id} className="border-b hover:bg-gray-50">
                <td className="p-2">{a.staffName}</td>
                <td className="p-2">{new Date(a.date).toLocaleDateString()}</td>
                <td className="p-2">{a.checkIn || '-'}</td>
                <td className="p-2">{a.checkOut || '-'}</td>
                <td className="p-2">
                  <span className={`px-2 py-1 rounded text-sm font-medium ${getStatusColor(a.status)}`}>
                    {a.status.toUpperCase()}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
